```js
const express = require('express');
const helmet = require('helmet');         // Security headers
const rateLimit = require('express-rate-limit'); // Rate limiting

const app = express();
const PORT = process.env.PORT || 3000;

// --- Security Middleware ---

// Set secure HTTP headers (XSS protection, nosniff, HSTS, etc.)
app.use(helmet());

// Rate limit all requests: max 100 per 15 minutes per IP
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// Parse JSON bodies with a size limit to prevent payload attacks
app.use(express.json({ limit: '10kb' }));

// --- Routes ---

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // In a real app: validate query params, paginate, and sanitize DB queries
  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ]);
});

// --- 404 Handler ---
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// --- Global Error Handler ---
// Must have 4 arguments for Express to treat it as an error handler
app.use((err, req, res, next) => {
  // Log the full error internally (use a real logger like `pino` in production)
  console.error(`[ERROR] ${err.stack || err.message}`);

  // Never expose internal error details to the client
  const status = err.status || err.statusCode || 500;
  const message =
    process.env.NODE_ENV === 'production'
      ? 'An unexpected error occurred.'
      : err.message;

  res.status(status).json({ error: message });
});

// --- Server Start ---
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

// Graceful shutdown on SIGTERM (important for containers/cloud environments)
process.on('SIGTERM', () => {
  server.close(() => {
    console.log('Server shut down gracefully.');
    process.exit(0);
  });
});

module.exports = app;
```

